import{_ as e,o,c as t,d as a}from"./app.22d6dd61.js";const f=JSON.parse('{"title":"Client Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"guide/configure/client-configuration.md","lastUpdated":1659428266000}'),i={name:"guide/configure/client-configuration.md"},n=a('<h1 id="client-configuration" tabindex="-1">Client Configuration <a class="header-anchor" href="#client-configuration" aria-hidden="true">#</a></h1><p>This tutorial will not go in detail about the options you can adjust with the client configuration settings. Instead, we will provide a broad overview of what is available in Iroha 2.</p><p>First, the <code>TORII_API_URL</code> is the same as <code>TORII</code> <code>API_ADDR</code> in the <a href="./peer-configuration.html">peer configuration</a>. You should also add either <code>http://</code> or (<em>preferably</em>) <code>https://</code> to the address.</p><p>If you are setting up an Iroha peer, you should set up a domain for public blockchains. Bare sockets are enough for a local private deployment.</p><p>The <code>ACCOUNT_ID</code> should be self-explanatory: the only thing you need to worry about, is that the account must exist in the blockchain. In the <a href="./genesis.html">example <code>genesis.json</code></a>, you can see how we set up the <em>alice</em>@wonderland account.</p>',5),r=[n];function c(s,d,l,h,u,p){return o(),t("div",null,r)}var g=e(i,[["render",c]]);export{f as __pageData,g as default};
